163→export const getCountNotificationsService = async (userId) => {
164→    const { data, error } = await supabase.rpc('get_unread_notification_count', {
165→        p_user_id: userId,
166→    });
167→
168→    if (error) {
169→        console.error('get_unread_notification_count rpc error:', error.message);
170→        throw { status: 500, error: 'error fetching count in notifications table' };
171→    }
172→
173→    return { count: data ?? 0 };
174→};
175→
176→export const readNotificationService = async (userId, notifId, source) => {
177→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
178→
179→    const { error } = await supabase
180→        .from(tableName)
181→        .update({ read: true })
182→        .eq('receiver_id', userId)
183→        .eq('id', notifId);
184→
185→    if (error) {
186→        console.error('error updating notification read status:', error);
187→        throw { status: 500, error: 'error updating the notification read status' };
188→    }
189→
190→    return { message: 'notification was read!' };
191→};
192→
193→export const deleteNotificationService = async (userId, notifId, source) => {
194→    if (!notifId) {
195→        throw { status: 400, error: 'notifId is required' };
196→    }
197→
198→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
199→
200→    const { error } = await supabase
201→        .from(tableName)
202→        .delete()
203→        .eq('receiver_id', userId)
204→        .eq('id', notifId);
205→
206→    if (error) {
207→        console.error('supabase error while deleting notification:', error.message);
208→        throw { status: 500, error: 'supabase error while deleting notification' };
209→    }
210→
211→    return { message: 'success' };
212→};
213→
214→export { NOTIFICATION_LIMIT_MIN, NOTIFICATION_LIMIT_MAX, NOTIFICATION_DEFAULT_LIMIT };
