 550→app.use((req, res, next) => {
 551→    metricsState.requests += 1;
 552→    metricsState.inFlight += 1;
 553→
 554→    const startNs = process.hrtime.bigint();
 555→    let byteCount = 0;
 556→
 557→    // Skip byte-counting overhead for cheap internal routes
 558→    const skipByteCount = req.path === '/health' || req.path === '/api/health'
 559→        || req.path === '/metrics' || req.path === '/api/metrics';
 560→
 561→    if (!skipByteCount) {
 562→        const originalWrite = res.write.bind(res);
 563→        const originalEnd = res.end.bind(res);
 564→
 565→        res.write = (chunk, encoding, callback) => {
 566→            if (chunk) {
 567→                byteCount += Buffer.isBuffer(chunk)
 568→                    ? chunk.length
 569→                    : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 570→            }
 571→            return originalWrite(chunk, encoding, callback);
 572→        };
 573→
 574→        res.end = (chunk, encoding, callback) => {
 575→            if (chunk) {
 576→                byteCount += Buffer.isBuffer(chunk)
 577→                    ? chunk.length
 578→                    : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 579→            }
 580→            return originalEnd(chunk, encoding, callback);
 581→        };
 582→    }
 583→
 584→    res.on('finish', () => {
 585→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 586→        metricsState.responses += 1;
 587→        metricsState.bytesSent += byteCount;
 588→
 589→        const statusBucket = classifyStatusBucket(res.statusCode);
 590→        metricsState.statusBuckets[statusBucket] += 1;
 591→
 592→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 593→        const routeTemplate = req.route?.path
 594→            ? `${req.baseUrl || ''}${req.route.path}`
 595→            : req.path;
 596→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 597→
 598→        let routeStat = metricsState.routeStats.get(routeKey);
 599→        if (!routeStat) {
 600→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 601→                return;
 602→            }
 603→
 604→            routeStat = {
 605→                count: 0,
 606→                totalDurationMs: 0,
 607→                maxDurationMs: 0,
 608→                bytesSent: 0,
 609→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 610→            };
 611→            metricsState.routeStats.set(routeKey, routeStat);
 612→        }
 613→
 614→        routeStat.count += 1;
 615→        routeStat.totalDurationMs += durationMs;
 616→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 617→        routeStat.bytesSent += byteCount;
 618→        routeStat.statusBuckets[statusBucket] += 1;
 619→    });
 620→
 621→    next();
 622→});
