414→export const addFollowsService = async(followerId, followingId) => {
415→    if(!followerId || !followingId){
416→        throw new AppError(400, 'followerId or followingId is undefined');
417→    }
418→
419→    const {data: existing, error: errorExisting} = await supabase
420→    .from('follows')
421→    .select('*')
422→    .eq('follower_id', followerId)
423→    .eq('following_id', followingId)
424→    .maybeSingle();
425→
426→    if(errorExisting){
427→        console.error('supabase error while checking existing following:', errorExisting.message);
428→        throw new AppError(500, 'supabase error while checking existing following');
429→    }
430→
431→    if(existing){
432→        const {error: errorRemoveData} = await supabase
433→        .from('follows')
434→        .delete()
435→        .eq('follower_id', followerId)
436→        .eq('following_id', followingId)
437→
438→        if(errorRemoveData){
439→            console.error('supabase error while deleting follow data:', errorRemoveData.message);
440→            throw new AppError(500, 'supabase error while deleting follow data');
441→        }
442→
443→        return {message: 'deleted follows data'};
444→    } else {
445→        const {error: errorInserData} = await supabase
446→        .from('follows')
447→        .insert({
448→            follower_id: followerId,
449→            following_id: followingId,
450→        })
451→
452→        if(errorInserData){
453→            console.error('supabase error while inserting follow data:', errorInserData.message);
454→            throw new AppError(500, 'supabase error while inserting follow data');
455→        }
456→
457→        // Create follow notification (skip if self-follow)
458→        if (followerId !== followingId) {
459→            await supabase
460→                .from('notifications')
461→                .insert({
462→                    sender_id: followerId,
463→                    receiver_id: followingId,
464→                    type: 'follow',
465→                    read: false
466→                });
467→        }
468→
469→        return {message: 'success'};
470→    }
471→}
