205→
206→    if (!username || typeof username !== 'string') {
207→        return res.status(400).json({ error: 'username is required' });
208→    }
209→
210→    const trimmed = username.trim();
211→    if (trimmed.length < 3 || trimmed.length > 50) {
212→        return res.status(400).json({ error: 'username must be 3-50 characters' });
