242→export const buildPathMatcher = (path = '') => {
243→    const candidates = listVariantPathsForDeletion(path).map((item) => escapeRegExp(item));
244→    if(candidates.length === 0){
245→        return null;
246→    }
247→    return new RegExp(`/(?:${candidates.join('|')})$`, 'i');
248→};
