362→
363→            return {
364→                bucket: bucket,
365→                path: path,
366→                name: item.name,
367→                createdAt: createdAt,
368→                timestamp: parseMediaTimestamp(item)
369→            };
370→        });
371→
372→    return {
373→        bucket: bucket,
374→        nextOffset: offset + listedItems.length,
375→        exhausted: listedItems.length < listLimit,
376→        items: normalizedItems,
377→        error: null
378→    };
