 41→const formatTimeAgo = (date) => {
 42→    if (!date) return '';
 43→    const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
 44→    if (seconds < 60) return 'just now';
 45→    const minutes = Math.floor(seconds / 60);
 46→    if (minutes < 60) return `${minutes}m ago`;
 47→    const hours = Math.floor(minutes / 60);
 48→    return `${hours}h ago`;
 49→};
