19→        nodes.forEach((node) => {
20→          if (node.__type === "image") {
21→            imageNodes.push({ key: node.__key, src: node.__src });
22→          }
23→        });
24→        setImages(imageNodes);
25→      });
26→    };
27→
28→    updateImages();
29→    return editor.registerUpdateListener(updateImages);
30→  }, [editor]);
