  1→import { useState, useRef } from "react";
  2→import { useAuth } from "../../Context/useAuth";
  3→import { addOpinion } from "../../../API/Api";
  4→import { BarLoader } from "react-spinners";
  5→import { useQueryClient } from "@tanstack/react-query";
  6→import { motion, AnimatePresence } from "framer-motion";
  7→import useTextareaMention from "../mentions/useTextareaMention";
  8→import MentionDropdown from "../mentions/MentionDropdown";
  9→
 10→const OpinionEditor = ({onClose}) =>{
 11→    const [opinion, setOpinion] = useState('');
 12→    const {session, user} = useAuth();
 13→    const [isSaving, setIsSaving] = useState(false);
 14→    const opinionTextareaRef = useRef(null);
 15→
 16→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(opinion, setOpinion, opinionTextareaRef, 280, user?.userData?.[0]?.id);
 17→
 18→    const queryClient = useQueryClient();
 19→
 20→    const handleCloseEditor = () =>{
 21→        onClose();
 22→    }
 23→
 24→    const handleClickSave = async(e) =>{
 25→        e.stopPropagation();
 26→        if(isSaving){
 27→            return;
 28→        }
 29→        const formdata = new FormData();
 30→        formdata.append('opinion', opinion)
 31→
 32→        try {
 33→            setIsSaving(true);
 34→            await addOpinion(formdata, session?.access_token);
 35→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 36→            queryClient.invalidateQueries({ queryKey: ['getMyOpinions'] });
 37→            setOpinion('');
 38→            onClose();
 39→        } catch (error) {
 40→            console.error('error uploading opinion:', error);
 41→        } finally {
 42→            setIsSaving(false);
 43→        }
 44→
 45→    }
 46→
 47→    const charCount = opinion.length;
 48→    const isNearLimit = charCount > 259;
 49→    const isAtLimit = charCount > 279;
 50→
 51→    return(
 52→        <AnimatePresence>
 53→        <motion.div
 54→            className="oe-backdrop"
 55→            initial={{opacity: 0}}
 56→            animate={{opacity: 1}}
 57→            exit={{opacity: 0}}
 58→            transition={{duration: 0.2}}
 59→            onClick={handleCloseEditor}
 60→        >
 61→            <motion.div
 62→                className="oe-card"
 63→                initial={{opacity: 0, scale: 0.95, y: 12}}
 64→                animate={{opacity: 1, scale: 1, y: 0, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
 65→                exit={{opacity: 0, scale: 0.95, y: 12, transition: {duration: 0.15, ease: 'easeOut'}}}
 66→                onClick={(e) => e.stopPropagation()}
 67→            >
 68→                <div className="oe-header">
 69→                    <p className="oe-title">Share your opinion</p>
 70→                    <button className="oe-close-btn" onClick={handleCloseEditor} aria-label="Close editor">
 71→                        <svg xmlns="http://www.w3.org/2000/svg" height="18px" viewBox="0 -960 960 960" width="18px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"></path></svg>
 72→                    </button>
 73→                </div>
 74→
 75→                <div className="oe-body">
 76→                    <textarea
 77→                        ref={opinionTextareaRef}
 78→                        maxLength={280}
 79→                        value={opinion}
 80→                        onChange={(e) => { setOpinion(e.target.value); mentionTextareaProps.onChange(e); }}
 81→                        onKeyDown={mentionTextareaProps.onKeyDown}
 82→                        onKeyUp={mentionTextareaProps.onKeyUp}
 83→                        className="oe-textarea"
 84→                        name="opinions"
 85→                        placeholder="What's on your mind..."
 86→                        rows={5}
 87→                    />
 88→                    <MentionDropdown {...mentionDropdownProps} />
 89→                </div>
 90→
 91→                <div className="oe-footer">
 92→                    <span className={`oe-char-count ${isAtLimit ? 'oe-char-limit' : isNearLimit ? 'oe-char-warn' : ''}`}>
 93→                        {charCount}/280
 94→                    </span>
 95→
 96→                    <button
 97→                        onClick={(e) => handleClickSave(e)}
 98→                        disabled={!opinion || isSaving}
 99→                        className={`oe-save-btn ${!opinion || isSaving ? 'oe-save-disabled' : ''}`}
100→                    >
101→                        {isSaving ? 'Saving...' : 'Post'}
102→                    </button>
103→                </div>
104→
105→                {isSaving && (
106→                    <div className="oe-loader">
107→                        <BarLoader loading={isSaving} width={'100%'} color="var(--accent-sage)" speedMultiplier={0.7}/>
108→                    </div>
109→                )}
110→            </motion.div>
111→        </motion.div>
112→        </AnimatePresence>
113→    )
114→}
115→
116→export default OpinionEditor;

