 40→const ChapterEditorInner = ({ chapter, storyId, chapterId, token, onBack }) => {
 41→    const [editor] = useLexicalComposerContext();
 42→    const navigate = useNavigate();
 43→    const updateChapter = useUpdateChapter(token);
 44→
 45→    const [chapterTitle, setChapterTitle] = useState(chapter?.title || '');
 46→    const [editorState, setEditorState] = useState(null);
 47→    const [wordCount, setWordCount] = useState(chapter?.word_count || 0);
 48→    const [isSaving, setIsSaving] = useState(false);
 49→    const [hasChanges, setHasChanges] = useState(false);
 50→    const saveTimerRef = useRef(null);
 51→    const uploadedImgPathsRef = useRef([]);
 52→
 53→    // Load existing content into editor
 54→    useEffect(() => {
 55→        if (chapter?.content && editor) {
 56→            try {
 57→                const content = typeof chapter.content === 'string'
 58→                    ? chapter.content
 59→                    : JSON.stringify(chapter.content);
 60→                const state = editor.parseEditorState(content);
 61→                editor.setEditorState(state);
 62→            } catch (err) {
 63→                console.error('Failed to load chapter content:', err);
 64→            }
 65→        }
 66→    }, [chapter?.id, editor]);
 67→
 68→    const onchange = useCallback((state) => {
 69→        const jsonStr = JSON.stringify(state.toJSON());
 70→        setEditorState(jsonStr);
 71→        setHasChanges(true);
 72→
 73→        state.read(() => {
 74→            const root = $getRoot();
 75→            const text = root.getTextContent().trim();
 76→            setWordCount(text ? text.split(/\s+/).length : 0);
 77→        });
 78→    }, []);
 79→
 80→    // Auto-save every 30 seconds
 81→    useEffect(() => {
 82→        if (!hasChanges || !editorState) return;
 83→
 84→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
 85→        saveTimerRef.current = setTimeout(() => {
 86→            handleSave(false);
 87→        }, 30000);
 88→
 89→        return () => {
 90→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
 91→        };
 92→    }, [editorState, hasChanges]);
 93→
 94→    const handleSave = async (showFeedback = true) => {
 95→        if (!editorState) return;
 96→        if (showFeedback) setIsSaving(true);
 97→
 98→        try {
 99→            await updateChapter.mutateAsync({
100→                storyId,
101→                chapterId,
102→                data: {
103→                    title: chapterTitle.trim() || 'Untitled Chapter',
104→                    content: editorState,
105→                },
106→            });
107→            setHasChanges(false);
108→        } catch (err) {
109→            console.error('Failed to save chapter:', err);
110→        } finally {
111→            if (showFeedback) setIsSaving(false);
112→        }
113→    };
114→
115→    const handlePublish = async () => {
116→        if (!editorState) return;
117→        setIsSaving(true);
118→        try {
119→            await updateChapter.mutateAsync({
120→                storyId,
121→                chapterId,
122→                data: {
123→                    title: chapterTitle.trim() || 'Untitled Chapter',
124→                    content: editorState,
125→                    status: 'published',
126→                },
127→            });
128→            setHasChanges(false);
129→            navigate(`/home/stories/${storyId}/manage`);
130→        } catch (err) {
131→            console.error('Failed to publish chapter:', err);
132→        } finally {
133→            setIsSaving(false);
134→        }
135→    };
136→
137→    const addUploadImagesPath = useCallback((paths) => {
138→        if (Array.isArray(paths)) {
139→            uploadedImgPathsRef.current = paths;
140→        } else if (paths) {
141→            uploadedImgPathsRef.current.push(paths);
142→        }
143→    }, []);
144→
145→    return (
146→        <>
147→            <div className="chapter-editor-header">
148→                <button className="chapter-editor-back" onClick={onBack}>
149→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
150→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
151→                    </svg>
152→                </button>
153→                <input
154→                    className="chapter-editor-title-input"
155→                    type="text"
156→                    value={chapterTitle}
157→                    onChange={(e) => {
158→                        setChapterTitle(e.target.value);
159→                        setHasChanges(true);
160→                    }}
161→                    placeholder="Chapter title..."
162→                    maxLength={200}
163→                />
164→                <div className="chapter-editor-header-actions">
165→                    <button
166→                        className="chapter-editor-save-btn"
167→                        onClick={() => handleSave(true)}
168→                        disabled={!hasChanges || isSaving}
169→                    >
170→                        {isSaving ? <BeatLoader size={6} color="var(--text-secondary)" /> : 'Save'}
171→                    </button>
172→                    <button
173→                        className="chapter-editor-publish-btn"
174→                        onClick={handlePublish}
175→                        disabled={isSaving}
176→                    >
177→                        Publish
178→                    </button>
179→                </div>
180→            </div>
181→
182→            <div className="chapter-editor-loader">
183→                {isSaving && (
184→                    <BarLoader loading={true} width="100%" height={3} color="var(--accent-purple)" speedMultiplier={0.7} />
185→                )}
186→            </div>
187→
188→            <div className="toolbar-wrapper">
189→                <ToolBar addUploadedImagePath={addUploadImagesPath} />
190→            </div>
191→
192→            <div className="chapter-editor-shell">
193→                <RichTextPlugin
194→                    contentEditable={
195→                        <ContentEditable
196→                            className="editor-input chapter-editor-content"
197→                            aria-placeholder="Start writing your chapter..."
198→                            placeholder={<div className="editor-placeholder">Start writing your chapter...</div>}
199→                        />
200→                    }
201→                    ErrorBoundary={LexicalErrorBoundary}
202→                />
203→                <ImagePlugin addUploadedImagePath={addUploadImagesPath} />
204→                <HistoryPlugin />
205→                <OnChangePlugin onChange={onchange} />
206→            </div>
207→
208→            <div className="chapter-editor-footer">
209→                <span className="chapter-editor-word-count">
210→                    {wordCount.toLocaleString()} {wordCount === 1 ? 'word' : 'words'}
211→                </span>
212→                {hasChanges && (
213→                    <span className="chapter-editor-unsaved">Unsaved changes</span>
214→                )}
215→            </div>
216→        </>
217→    );
218→};
