362→.editor-placeholder {
363→    color: var(--text-muted);
364→    overflow: hidden;
365→    position: absolute;
366→    top: -4px;
367→    user-select: none;
368→    pointer-events: none;
369→    margin: 0;
370→}
371→.editor-paragraph {
372→    margin: 0;
373→}
374→.editor-heading-h1 {
375→    margin: 0.9rem 0 0.45rem;
376→    font-size: 1.75rem;
377→    font-weight: 700;
378→    line-height: 1.25;
379→    color: var(--text-heading);
380→}
381→.editor-heading-h2 {
382→    margin: 0.8rem 0 0.4rem;
383→    font-size: 1.4rem;
384→    font-weight: 650;
385→    line-height: 1.3;
386→    color: var(--text-heading);
387→}
388→.editor-heading-h3 {
389→    margin: 0.7rem 0 0.35rem;
390→    font-size: 1.15rem;
391→    font-weight: 600;
392→    line-height: 1.35;
393→    color: var(--text-heading);
394→}
395→.editor-quote {
396→    margin: 0.5rem 0;
397→    padding: 0.3rem 0.65rem;
398→    border-left: 2px solid var(--editor-accent);
399→    background: color-mix(in srgb, var(--editor-accent) 5%, transparent);
400→    color: var(--editor-text);
401→    font-style: italic;
402→}
403→
404→/* ── Footer bar (word count + save status + buttons) ── */
405→.editor-footer {
406→    display: flex;
407→    justify-content: space-between;
408→    align-items: center;
409→    padding: 0.5rem 0;
410→    border-top: 1px solid var(--editor-border);
411→    margin-top: auto;
412→    gap: 0.5rem;
413→}
414→.editor-footer-left {
415→    display: flex;
416→    align-items: center;
417→    gap: 0.75rem;
418→    min-width: 0;
419→}
420→.editor-footer-actions {
421→    display: flex;
422→    align-items: center;
423→    gap: 0.5rem;
424→    flex-shrink: 0;
425→}
426→.editor-word-count {
427→    font-size: 0.8rem;
428→    color: var(--text-muted);
429→    user-select: none;
430→    padding-left: 0.25rem;
431→    white-space: nowrap;
432→}
433→.editor-save-status {
434→    font-size: 0.75rem;
435→    user-select: none;
436→    white-space: nowrap;
437→}
438→.editor-save-status--saving {
439→    color: var(--text-muted);
440→}
441→.editor-save-status--saved {
442→    color: var(--text-muted);
443→}
444→.editor-save-status--unsaved {
445→    color: var(--accent-amber, #d4a017);
446→}
447→
448→/* ── Bar loader positioning ── */
449→.editor-loader-wrapper {
450→    height: 4px;
451→    flex-shrink: 0;
452→}
453→
454→/* ── Save button ── */
455→.editor-save-bttn {
456→    display: flex;
457→    justify-content: center;
458→    align-items: center;
459→    padding: 0.5rem 1.25rem;
460→    border-radius: 15px;
461→    background-color: var(--editor-accent);
462→    color: #ffffff;
463→    font-weight: 650;
464→    cursor: pointer;
465→    border: none;
466→    transition: background-color 0.15s ease, transform 0.1s ease, opacity 0.15s ease;
467→}
468→.editor-save-bttn:hover {
469→    opacity: 0.9;
470→}
471→.editor-save-bttn:active {
472→    transform: scale(0.98);
473→}
474→.editor-save-bttn:focus {
475→    outline: none;
476→}
477→.editor-save-bttn-disabled {
478→    display: flex;
479→    justify-content: center;
480→    align-items: center;
481→    padding: 0.5rem 1.25rem;
482→    border-radius: 15px;
483→    background-color: var(--bg-pill);
484→    color: var(--text-muted);
485→    font-weight: 650;
486→    user-select: none;
487→    border: none;
488→    cursor: not-allowed;
489→}
490→.editor-save-bttn-disabled:focus {
491→    outline: none;
492→}
493→
494→/* ── Draft button ── */
495→.editor-draft-bttn {
496→    display: flex;
497→    justify-content: center;
498→    align-items: center;
499→    padding: 0.5rem 1rem;
500→    border-radius: 15px;
501→    background-color: transparent;
502→    color: var(--editor-text);
503→    font-weight: 600;
504→    cursor: pointer;
505→    border: 1.5px solid var(--editor-border);
506→    transition: background-color 0.15s ease, border-color 0.15s ease, transform 0.1s ease;
507→    font-size: 0.875rem;
508→}
509→.editor-draft-bttn:hover {
510→    background-color: var(--bg-pill);
511→    border-color: var(--text-muted);
512→}
513→.editor-draft-bttn:active {
514→    transform: scale(0.98);
515→}
516→.editor-draft-bttn:focus {
517→    outline: none;
518→}
519→.editor-draft-bttn-disabled {
520→    display: flex;
521→    justify-content: center;
522→    align-items: center;
523→    padding: 0.5rem 1rem;
524→    border-radius: 15px;
525→    background-color: transparent;
526→    color: var(--text-muted);
527→    font-weight: 600;
528→    border: 1.5px solid var(--editor-border);
529→    cursor: not-allowed;
530→    opacity: 0.5;
531→    font-size: 0.875rem;
532→}
533→.editor-draft-bttn-disabled:focus {
534→    outline: none;
535→}
536→
537→/* ── Image upload icon (inside toolbar) ── */
538→.editor-upload-image-icon {
539→    padding: 0.4rem;
540→    border-radius: 6px;
541→    cursor: pointer;
542→    transition: all 0.15s ease;
543→}
544→.editor-upload-image-icon:hover {
545→    background-color: var(--bg-pill);
546→}
547→
548→/* ── Image components ── */
549→.image-container {
550→    display: flex;
551→    justify-content: center;
552→    width: 100%;
553→    height: fit-content;
554→}
555→.image-wrapper {
556→    position: relative;
557→    display: flex;
558→    justify-content: flex-end;
559→    margin: 1rem 0;
560→    width: fit-content;
561→    height: fit-content;
562→}
563→.image-actions {
564→    position: absolute;
565→    display: flex;
566→    gap: 0.3rem;
567→    top: 0;
568→    right: 0;
569→    margin: 0.5rem;
570→    z-index: 11;
571→}
572→.image-action-btn {
573→    display: flex;
574→    align-items: center;
575→    justify-content: center;
576→    padding: 0.4rem;
577→    border-radius: 50%;
578→    cursor: pointer;
579→    transition: ease-in-out 0.1s;
580→    background-color: rgba(0, 0, 0, 0.35);
581→}
582→.image-action-btn:hover {
583→    background-color: rgba(0, 0, 0, 0.55);
584→}
585→.dimension-display {
586→    position: absolute;
587→    display: flex;
588→    justify-content: center;
589→    align-items: center;
590→    top: -35px;
591→    left: 50%;
592→    transform: translateX(-50%);
593→    background-color: var(--bg-pill);
594→    color: var(--text-muted);
595→    padding: 0.4rem 0.5rem;
596→    white-space: nowrap;
597→    pointer-events: none;
598→    font-size: 0.8rem;
599→    border-radius: 4px;
600→}
601→
602→/* ── Resize handles ── */
603→.southeast-side-handle {
604→    position: absolute;
605→    bottom: -4px;
606→    right: -4px;
607→    width: 12px;
608→    height: 12px;
609→    background-color: var(--bg-pill);
610→    border: 1px solid var(--editor-text);
611→    border-radius: 50%;
612→    cursor: nwse-resize;
613→    z-index: 10;
614→}
615→.southwest-side-handle {
616→    position: absolute;
617→    bottom: -4px;
618→    left: -4px;
619→    width: 12px;
620→    height: 12px;
621→    background-color: var(--bg-pill);
622→    border: 1px solid var(--editor-text);
623→    border-radius: 50%;
624→    cursor: nesw-resize;
625→    z-index: 10;
626→}
627→.northeast-side-handle {
628→    position: absolute;
629→    top: -4px;
630→    right: -4px;
631→    width: 12px;
632→    height: 12px;
633→    background-color: var(--bg-pill);
634→    border: 1px solid var(--editor-text);
635→    border-radius: 50%;
636→    cursor: sw-resize;
637→    z-index: 10;
638→}
639→.northwest-side-handle {
640→    position: absolute;
641→    top: -4px;
642→    left: -4px;
643→    width: 12px;
644→    height: 12px;
645→    background-color: var(--bg-pill);
646→    border: 1px solid var(--editor-text);
647→    border-radius: 50%;
648→    cursor: se-resize;
649→    z-index: 10;
650→}
651→.east-side-handle {
652→    position: absolute;
653→    top: 50%;
654→    right: -4px;
655→    width: 8px;
656→    height: 20px;
657→    background-color: var(--bg-pill);
658→    border: 1px solid var(--editor-text);
659→    border-radius: 2px;
660→    transform: translateY(-50%);
661→    cursor: ew-resize;
662→    z-index: 10;
663→}
664→.south-side-handle {
665→    position: absolute;
666→    bottom: -4px;
667→    left: 50%;
668→    width: 20px;
669→    height: 8px;
670→    background-color: var(--bg-pill);
671→    border: 1px solid var(--editor-text);
672→    border-radius: 2px;
673→    transform: translateX(-50%);
674→    cursor: ns-resize;
675→    z-index: 10;
676→}
677→.north-side-handle {
678→    position: absolute;
679→    top: -4px;
680→    left: 50%;
681→    width: 20px;
682→    height: 8px;
683→    background-color: var(--bg-pill);
684→    border: 1px solid var(--editor-text);
685→    border-radius: 2px;
686→    transform: translateX(-50%);
687→    cursor: nw-resize;
688→    z-index: 10;
689→}
690→
691→/* ── Image loading overlay ── */
692→.image-loading-overlay {
693→    position: absolute;
694→    top: 0;
695→    left: 0;
696→    width: 100%;
697→    height: 100%;
698→    display: flex;
699→    flex-direction: column;
700→    justify-content: center;
701→    align-items: center;
702→    background-color: rgba(0, 0, 0, 0.45);
703→    border-radius: 5px;
704→    gap: 8px;
705→    pointer-events: none;
706→}
707→.image-loading-spinner {
708→    width: 28px;
709→    height: 28px;
710→    border: 3px solid rgba(255, 255, 255, 0.2);
711→    border-top: 3px solid var(--editor-accent);
712→    border-radius: 50%;
713→    animation: image-spin 0.8s linear infinite;
714→}
715→@keyframes image-spin {
716→    0% { transform: rotate(0deg); }
717→    100% { transform: rotate(360deg); }
718→}
719→
720→/* ── Full-screen image view ── */
721→.image-view {
722→    position: fixed;
723→    top: 0;
724→    left: 0;
725→    width: 100vw;
726→    height: 100vh;
727→    object-fit: contain;
728→    background: rgba(0, 0, 0, 0.7);
729→    z-index: 9999;
730→    cursor: zoom-out;
731→    box-sizing: border-box;
732→}
733→
734→/* ── Close confirmation dialog ── */
735→.editor-close-confirm-overlay {
736→    position: absolute;
737→    inset: 0;
738→    display: flex;
739→    justify-content: center;
740→    align-items: center;
741→    background-color: rgba(0, 0, 0, 0.4);
742→    backdrop-filter: blur(4px);
743→    border-radius: 16px;
744→    z-index: 20;
745→    cursor: pointer;
746→}
747→.editor-close-confirm-card {
748→    display: flex;
749→    flex-direction: column;
750→    align-items: center;
751→    gap: 1.25rem;
752→    padding: 1.5rem 2rem;
753→    background-color: var(--editor-bg);
754→    border: 1px solid var(--editor-border);
755→    border-radius: 14px;
756→    box-shadow: var(--shadow-modal);
757→    max-width: 320px;
758→    width: 90%;
759→    cursor: default;
760→}
761→.editor-close-confirm-message {
762→    margin: 0;
763→    font-size: 1rem;
764→    font-weight: 600;
765→    color: var(--editor-text);
766→    text-align: center;
767→    line-height: 1.4;
768→}
769→.editor-close-confirm-actions {
770→    display: flex;
771→    gap: 0.75rem;
772→    width: 100%;
773→}
774→.editor-close-confirm-discard {
775→    flex: 1;
776→    padding: 0.5rem 1rem;
777→    border-radius: 12px;
778→    background-color: transparent;
779→    color: var(--editor-text);
780→    font-weight: 600;
781→    font-size: 0.875rem;
782→    cursor: pointer;
783→    border: 1.5px solid var(--editor-border);
784→    transition: background-color 0.15s ease, border-color 0.15s ease;
785→}
786→.editor-close-confirm-discard:hover {
787→    background-color: var(--bg-pill);
788→    border-color: var(--text-muted);
789→}
790→.editor-close-confirm-discard:disabled {
791→    opacity: 0.5;
792→    cursor: not-allowed;
793→}
794→.editor-close-confirm-save {
795→    flex: 1;
796→    padding: 0.5rem 1rem;
797→    border-radius: 12px;
798→    background-color: var(--editor-accent);
799→    color: #ffffff;
800→    font-weight: 650;
801→    font-size: 0.875rem;
802→    cursor: pointer;
803→    border: none;
804→    transition: opacity 0.15s ease;
805→}
806→.editor-close-confirm-save:hover {
807→    opacity: 0.9;
808→}
809→.editor-close-confirm-save:disabled {
810→    opacity: 0.6;
811→    cursor: not-allowed;
812→}
813→.editor-close-confirm-error {
814→    margin: -0.75rem 0 0;
815→    font-size: 0.8rem;
816→    color: var(--accent-amber, #d4a017);
