 72→    const normalizeColor = (value) => {
 73→        if (!value) return '';
 74→        const trimmed = value.trim().toLowerCase();
 75→        if (!trimmed.startsWith('#')) {
 76→            return toCompactRgb(trimmed);
 77→        }
 78→
 79→        let hex = trimmed.slice(1);
 80→        if (hex.length === 3) {
 81→            hex = hex.split('').map((char) => `${char}${char}`).join('');
 82→        }
 83→        if (hex.length !== 6) {
 84→            return trimmed;
 85→        }
 86→
 87→        const r = parseInt(hex.slice(0, 2), 16);
 88→        const g = parseInt(hex.slice(2, 4), 16);
 89→        const b = parseInt(hex.slice(4, 6), 16);
 90→
 91→        return `rgb(${r},${g},${b})`;
 92→    };
