### Phase 7 — Image paste/drop

**Goal:** Users can paste or drag-and-drop images directly into the editor.

**New file:** `client/src/components/HomePage/Editor/plugins/PasteImagePlugin.jsx`

This plugin handles two events:
1. `paste` event on the editor root element — checks `clipboardData.files` for image files
2. `drop` event on the editor root element — checks `dataTransfer.files` for image files

Both paths share the same upload function: create a blob URL, dispatch `INSERT_IMAGE_COMMAND` with `loading: true`, upload to backend, replace blob URL with real URL (same pattern as the existing `insertImageFromFile` in Toolbar.jsx).

The plugin needs the `addUploadedImagePath` callback and the auth token, so it receives these as props.

```jsx
// PasteImagePlugin.jsx
import { useEffect } from 'react';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { INSERT_IMAGE_COMMAND } from '../nodes/ImageNode';
import { saveJournalImage } from '../../../../../API/Api';

export default function PasteImagePlugin({ addUploadedImagePath, token }) {
  const [editor] = useLexicalComposerContext();

  useEffect(() => {
    const root = editor.getRootElement();
    if (!root) return;

    const handleFiles = async (files) => {
      for (const file of files) {
        if (!file.type.startsWith('image/')) continue;
        const blobUrl = URL.createObjectURL(file);
        editor.dispatchCommand(INSERT_IMAGE_COMMAND, { src: blobUrl, width: 500, height: 500, loading: true });

        try {
          const formdata = new FormData();
          formdata.append('image', file);
          const data = await saveJournalImage(token, formdata);
          if (data?.img_url) {
            const filePath = data.img_url.split('/journal-images/').pop();
            if (filePath && addUploadedImagePath) addUploadedImagePath(filePath);
            editor.update(() => {
              const nodeMap = editor.getEditorState()._nodeMap;
              for (const [, node] of nodeMap) {
                if (node.__type === 'image' && node.__src === blobUrl) {
                  node.getWritable().__src = data.img_url;
                  node.getWritable().__loading = false;
                  break;
                }
              }
            });
            URL.revokeObjectURL(blobUrl);
          }
        } catch (err) {
          console.error('Paste image upload failed:', err);
        }
      }
    };

    const onPaste = (e) => {
      const files = Array.from(e.clipboardData?.files || []);
      if (files.some(f => f.type.startsWith('image/'))) {
        e.preventDefault();
        handleFiles(files);
      }
    };

    const onDrop = (e) => {
      const files = Array.from(e.dataTransfer?.files || []);
      if (files.some(f => f.type.startsWith('image/'))) {
        e.preventDefault();
        handleFiles(files);
      }
    };

    root.addEventListener('paste', onPaste);
    root.addEventListener('drop', onDrop);
    root.addEventListener('dragover', (e) => e.preventDefault()); // required for drop to work

    return () => {
      root.removeEventListener('paste', onPaste);
      root.removeEventListener('drop', onDrop);
    };
  }, [editor, token, addUploadedImagePath]);

  return null;
}
```

Register in `RichTextEditor.jsx` with `addUploadedImagePath={addUploadImagesPath}` and `token={session?.access_token}`.

