### Phase 5 — Floating selection toolbar (critical for mobile)

**Goal:** A mini toolbar that appears above any text selection, with the 6 most-used formatting actions. This is the core mobile experience improvement.

**New file:** `client/src/components/HomePage/Editor/plugins/FloatingSelectionToolbar.jsx`

This component:
1. Uses `editor.registerUpdateListener` to detect when a non-collapsed range selection exists
2. Positions a floating pill above the selection using `window.getSelection().getRangeAt(0).getBoundingClientRect()`
3. Shows: Bold, Italic, Underline, Strikethrough, Link, Inline code
4. Each button dispatches the appropriate FORMAT_TEXT_COMMAND immediately (no state flip needed — the toolbar button closes on selection change anyway)
5. Disappears when selection collapses

Key considerations:
- Must render via `createPortal` to escape the modal's stacking context
- Must `onMouseDown={(e) => e.preventDefault()}` on the container to prevent deselection
- Position must clamp to viewport edges — subtract popup width/2 from selection center, then clamp to `[8, viewport_width - popup_width - 8]`
- Vertical: place 8px above `rect.top`. If that goes off-screen top, flip to below `rect.bottom`

```jsx
// FloatingSelectionToolbar.jsx
import { createPortal } from 'react-dom';
import { FORMAT_TEXT_COMMAND, $getSelection, $isRangeSelection } from 'lexical';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { useEffect, useRef, useState } from 'react';

const TOOLBAR_HEIGHT = 42;
const TOOLBAR_GAP = 8;

export default function FloatingSelectionToolbar({ onLinkClick }) {
  const [editor] = useLexicalComposerContext();
  const [coords, setCoords] = useState(null);
  const [activeFormats, setActiveFormats] = useState({});
  const ref = useRef(null);

  useEffect(() => {
    return editor.registerUpdateListener(({ editorState }) => {
      editorState.read(() => {
        const selection = $getSelection();
        if (!$isRangeSelection(selection) || selection.isCollapsed()) {
          setCoords(null);
          return;
        }

        const nativeSel = window.getSelection();
        if (!nativeSel || nativeSel.rangeCount === 0) return;

        const range = nativeSel.getRangeAt(0);
        const rect = range.getBoundingClientRect();

        const toolbarWidth = ref.current?.offsetWidth || 280;
        const x = Math.max(8, Math.min(
          rect.left + rect.width / 2 - toolbarWidth / 2,
          window.innerWidth - toolbarWidth - 8
        ));
        const y = rect.top - TOOLBAR_HEIGHT - TOOLBAR_GAP < 0
          ? rect.bottom + TOOLBAR_GAP
          : rect.top - TOOLBAR_HEIGHT - TOOLBAR_GAP;

        setCoords({ x, y: y + window.scrollY });
        setActiveFormats({
          bold: selection.hasFormat('bold'),
          italic: selection.hasFormat('italic'),
          underline: selection.hasFormat('underline'),
          strikethrough: selection.hasFormat('strikethrough'),
          code: selection.hasFormat('code'),
        });
      });
    });
  }, [editor]);

  if (!coords) return null;

  const fmt = (f) => editor.dispatchCommand(FORMAT_TEXT_COMMAND, f);

  return createPortal(
    <div
      ref={ref}
      className="floating-selection-toolbar"
      style={{ top: coords.y, left: coords.x }}
      onMouseDown={(e) => e.preventDefault()}
    >
      <button className={activeFormats.bold ? 'fst-btn fst-active' : 'fst-btn'} onClick={() => fmt('bold')}>{/* B icon */}</button>
      <button className={activeFormats.italic ? 'fst-btn fst-active' : 'fst-btn'} onClick={() => fmt('italic')}>{/* I icon */}</button>
      <button className={activeFormats.underline ? 'fst-btn fst-active' : 'fst-btn'} onClick={() => fmt('underline')}>{/* U icon */}</button>
      <button className={activeFormats.strikethrough ? 'fst-btn fst-active' : 'fst-btn'} onClick={() => fmt('strikethrough')}>{/* S icon */}</button>
      <button onClick={onLinkClick} className="fst-btn">{/* Link icon */}</button>
      <button className={activeFormats.code ? 'fst-btn fst-active' : 'fst-btn'} onClick={() => fmt('code')}>{/* Code icon */}</button>
    </div>,
    document.body
  );
}
```

The `onLinkClick` prop bridges to `FloatingLinkEditor` — clicking the link button in `FloatingSelectionToolbar` should open the link input popup anchored to the selection.

